sql:
SELECT experiment_id 
FROM experiment_feedback 
WHERE rating = 5;

SELECT AVG(rating) AS avg_rating
FROM experiment_feedback
WHERE experiment_id = 1;

SELECT COUNT(DISTINCT subj_id) 
FROM experiments 
WHERE experiment_id = 1;

SELECT COUNT(DISTINCT subj_id)
FROM experiments
WHERE duration > 500;

SELECT experiment_name
FROM experiments
WHERE researcher_id = (SELECT MAX(researcher_id) FROM experiments);

SELECT email 
FROM participants
WHERE subj_id = '1';

SELECT SUM(duration) AS total_duration
FROM experiments
WHERE created_at >= strftime('%Y-%m-%d', 'now', '-6 months');
